function twoSumFast(nums, target) {
  const map = {};
  for (let i = 0; i < nums.length; i++) {
    const c = target - nums[i];
    if (map[c] !== undefined) return [map[c], i];
    map[nums[i]] = i;
  }
}

function maxSubarraySum(arr, k) {
  let ws = 0;
  for (let i = 0; i < k; i++) ws += arr[i];
  let mx = ws;
  for (let i = k; i < arr.length; i++) { ws += arr[i]-arr[i-k]; mx = Math.max(mx,ws); }
  return mx;
}

class TreeNode {
  constructor(val) { this.val=val; this.left=null; this.right=null; }
}
function buildTree() {
  const r = new TreeNode(1);
  r.left = new TreeNode(2); r.right = new TreeNode(3);
  r.left.left = new TreeNode(4); r.left.right = new TreeNode(5);
  return r;
}

function maxDepth(root) {
  if (!root) return 0;
  return 1 + Math.max(maxDepth(root.left), maxDepth(root.right));
}

function inOrder(root) {
  const r = [];
  function go(n) { if(!n)return; go(n.left); r.push(n.val); go(n.right); }
  go(root); return r;
}

function isPalindrome(s) {
  s = s.toLowerCase().replace(/[^a-z0-9]/g,'');
  let l=0, r=s.length-1;
  while(l<r) { if(s[l]!==s[r]) return false; l++; r--; }
  return true;
}

function frequency(arr) {
  const f = {};
  for (const x of arr) f[x] = (f[x]||0)+1;
  return f;
}

function isValid(s) {
  const st=[], m={')':'(','}':'{',']':'['};
  for(const c of s){
    if('({['.includes(c)) st.push(c);
    else if(st.pop()!==m[c]) return false;
  }
  return st.length===0;
}

function mergeSorted(a, b) {
  const r=[]; let i=0,j=0;
  while(i<a.length&&j<b.length) a[i]<=b[j]?r.push(a[i++]):r.push(b[j++]);
  while(i<a.length) r.push(a[i++]);
  while(j<b.length) r.push(b[j++]);
  return r;
}

function binarySearch(arr, target) {
  let l=0, r=arr.length-1;
  while(l<=r) {
    const m=Math.floor((l+r)/2);
    if(arr[m]===target) return m;
    arr[m]<target ? l=m+1 : r=m-1;
  }
  return -1;
}

class ListNode {
  constructor(val) { this.val=val; this.next=null; }
}
function buildList(arr) {
  if(!arr.length) return null;
  const h=new ListNode(arr[0]); let c=h;
  for(let i=1;i<arr.length;i++){c.next=new ListNode(arr[i]);c=c.next;}
  return h;
}

function reverseList(head) {
  let prev=null, cur=head;
  while(cur) { const n=cur.next; cur.next=prev; prev=cur; cur=n; }
  return prev;
}

function fib(n, memo={}) {
  if(n===0) return 0; if(n===1) return 1;
  if(memo[n]!==undefined) return memo[n];
  memo[n]=fib(n-1,memo)+fib(n-2,memo);
  return memo[n];
}

function lengthOfLongest(s) {
  const seen={}; let l=0,mx=0;
  for(let r=0;r<s.length;r++){
    if(seen[s[r]]!==undefined&&seen[s[r]]>=l) l=seen[s[r]]+1;
    seen[s[r]]=r; mx=Math.max(mx,r-l+1);
  }
  return mx;
}

function groupAnagrams(strs) {
  const m={};
  for(const s of strs){const k=s.split('').sort().join('');if(!m[k])m[k]=[];m[k].push(s);}
  return Object.values(m);
}

function productExceptSelf(nums) {
  const n=nums.length, r=new Array(n).fill(1);
  let p=1; for(let i=0;i<n;i++){r[i]=p;p*=nums[i];}
  let s=1; for(let i=n-1;i>=0;i--){r[i]*=s;s*=nums[i];}
  return r;
}

function hasCycle(head) {
  let s=head, f=head;
  while(f&&f.next) { s=s.next; f=f.next.next; if(s===f) return true; }
  return false;
}

function mergeSort(arr) {
  if(arr.length<=1) return arr;
  const m=Math.floor(arr.length/2);
  const l=mergeSort(arr.slice(0,m)), r=mergeSort(arr.slice(m));
  const res=[]; let i=0,j=0;
  while(i<l.length&&j<r.length) l[i]<=r[j]?res.push(l[i++]):res.push(r[j++]);
  while(i<l.length) res.push(l[i++]);
  while(j<r.length) res.push(r[j++]);
  return res;
}

function hasPathSum(root, t) {
  if(!root) return false;
  if(!root.left&&!root.right) return root.val===t;
  return hasPathSum(root.left,t-root.val)||hasPathSum(root.right,t-root.val);
}

function maxSubarray(nums) {
  let cur=nums[0], mx=nums[0];
  for(let i=1;i<nums.length;i++){cur=Math.max(nums[i],cur+nums[i]);mx=Math.max(mx,cur);}
  return mx;
}

function firstUnique(s) {
  const f={};
  for(const c of s) f[c]=(f[c]||0)+1;
  for(let i=0;i<s.length;i++) if(f[s[i]]===1) return i;
  return -1;
}

class MyQueue {
  constructor() { this.s1=[]; this.s2=[]; }
  enqueue(v) { this.s1.push(v); }
  dequeue() {
    if(!this.s2.length) while(this.s1.length) this.s2.push(this.s1.pop());
    return this.s2.pop();
  }
}
